const labels = {1: 'Excellent', 2: 'Good', 3: 'Moderate', 4: 'Poor', 5: 'Unhealthy'};
const aqi = msg.payload.aqi;
const label = labels[aqi] || 'Unknown';
msg.payload = {
    aqi: aqi,
    label: label,
    tvoc: msg.payload.tvocPpb + ' ppb',
    eco2: msg.payload.eco2Ppm + ' ppm'
};
return msg;
